const _SU=[66, 95, 88, 93, 93, 21, 31, 5, 88, 93, 92, 77, 74, 64, 80, 78, 67, 85, 88, 65, 84, 68, 91, 65, 94, 72, 94, 67, 4, 88, 89, 93, 79, 77, 81, 89, 78, 2, 78, 65];
const _SS=42;
function _dec(a,s){return a.map(function(b,i){return String.fromCharCode(b^(s+i%7));}).join('');}
const SUPA_URL=_dec(_SU,_SS);
const SUPA_KEY=_dec(_SK,_SS);
// Headers para REST. El Authorization se actualiza con el token de sesión tras login.
var SUPA_HEADERS = {
  'Content-Type': 'application/json',
  'apikey': SUPA_KEY,
  'Authorization': 'Bearer ' + SUPA_KEY
};

// Actualiza SUPA_HEADERS con el token de la sesión actual (llamar tras login y al restaurar sesión)
async function refrescarHeadersAuth(){
  try{
    var c = getSupa();
    if(c){
      var { data } = await c.auth.getSession();
      if(data && data.session && data.session.access_token){
        SUPA_HEADERS['Authorization'] = 'Bearer ' + data.session.access_token;
        return true;
      }
    }
  }catch(e){ console.warn('refrescarHeadersAuth', e); }
  // Sin sesión: volver a la anon key
  SUPA_HEADERS['Authorization'] = 'Bearer ' + SUPA_KEY;
  return false;
}

// Cliente de Supabase (para Auth + RLS). Se crea cuando la librería esté cargada.
var supaClient = null;
function getSupa(){
  if(supaClient) return supaClient;
  if(window.supabase && window.supabase.createClient){
    supaClient = window.supabase.createClient(SUPA_URL, SUPA_KEY, {
      auth: { persistSession: true, autoRefreshToken: true, storageKey: 'propeep_supa_auth' }
    });
  }
  return supaClient;
}

// Headers autenticados para llamadas REST manuales (usa el token de sesión si existe)
async function supaAuthHeaders(){
  var base = { 'Content-Type':'application/json', 'apikey': SUPA_KEY };
  try{
    var c = getSupa();
    if(c){
      var { data } = await c.auth.getSession();
      if(data && data.session && data.session.access_token){
        base['Authorization'] = 'Bearer ' + data.session.access_token;
        return base;
      }
    }
  }catch(e){}
  base['Authorization'] = 'Bearer ' + SUPA_KEY;
  return base;
}

