// CREDENCIALES (mismo esquema original)
// ══════════════════════════════════════════
const _U = '';

function _getUsers(){
  try{
    const bytes = Uint8Array.from(atob(_U), c => c.charCodeAt(0));
    const decoded = new TextDecoder('utf-8').decode(bytes);
    return JSON.parse(decoded);
  }catch(e){ console.warn('_getUsers error', e); return []; }
}

